/****** Object:  View [dbo].[vw_AuditoriaRecente]    Script Date: 08/12/2025 10:07:28 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE VIEW [dbo].[vw_AuditoriaRecente]
AS
SELECT TOP 1000
    Id,
    Tabela,
    Operacao,
    ChaveRegistro,
    Usuario,
    DataHora,
    DadosAnteriores,
    DadosNovos,
    IP,
    Estacao
FROM [dbo].[LogAuditoria]
ORDER BY DataHora DESC;

